ucs.kql:
// MirrorFace LODEINFO/NOOPDOOR/ANEL side-loading from user-writable path
let Lookback = 7d;
let BaselineDays = 30d;
let UserWritable = dynamic([@"\users\", @"\appdata\", @"\programdata\", @"\public\", @"\temp\", @"\perflogs\", @"\downloads\"]);
// Known MirrorFace side-load host binaries (publicly reported by JPCERT/Trend/ESET)
let HostBins = dynamic(["k7sysmon.exe","k7tsecurity.exe","k7avmscn.exe","jsesprt.exe","jsschhlp.exe","jslogd.exe","vfhost.exe","mscorsvw.exe","javaw.exe","jusched.exe"]);
// 30-day baseline of (parent_dir, host_bin, dll) triplets — exclude anything we have seen before in the org
let Baseline = DeviceImageLoadEvents
    | where Timestamp between (ago(BaselineDays) .. ago(Lookback))
    | where InitiatingProcessFileName has_any (HostBins)
    | summarize by InitiatingProcessFileName, FileName, FolderPath;
DeviceImageLoadEvents
| where Timestamp > ago(Lookback)
| where InitiatingProcessFileName has_any (HostBins)
// Host binary itself dropped to a user-writable path (NOT C:\Program Files\…)
| where tolower(InitiatingProcessFolderPath) has_any (UserWritable)
// DLL sits next to the host binary (classic search-order hijack)
| where tolower(FolderPath) == tolower(InitiatingProcessFolderPath)
// Loaded module is NOT signed by Microsoft / not a Windows system path
| where FolderPath !startswith @"C:\Windows\"
   and FolderPath !startswith @"C:\Program Files"
| where InitiatingProcessAccountName !endswith "$"
// Anti-baseline — first time the org has seen this triplet
| join kind=leftanti Baseline on InitiatingProcessFileName, FileName, FolderPath
| extend FileSizeKB = FileSize / 1024
| project Timestamp, DeviceName, AccountName = InitiatingProcessAccountName,
          HostBin = InitiatingProcessFileName,
          HostBinPath = InitiatingProcessFolderPath,
          HostBinSHA256 = InitiatingProcessSHA256,
          SideLoadedDLL = FileName,
          DLLFolder = FolderPath,
          DLLSHA256 = SHA256,
          FileSizeKB,
          ParentCmd = InitiatingProcessCommandLine
| order by Timestamp desc
